import Foundation

// MARK: - Models

/// A simple example model for successful decoding.
struct FetchedData: Codable {
    let id: Int
    let message: String
}

// MARK: - Networking Service

enum DataFetchError: Error {
    case invalidURL
    case decodingError(Error)
    case networkError(URLError)
}

/// Fetches and decodes the data into the specified type.
/// - Parameter url: The URL to fetch data from.
/// - Returns: A Result containing the decoded object or a specific error.
func fetchData<T: Decodable>(from url: URL) async -> Result<T> {
    do {
        let (data, response) = try await URLSession.shared.data(from: url)

        guard let httpResponse = response as? HTTPURLResponse else {
            // Handle unexpected response type if needed, though usually the body contains the error.
            return.failure(DataFetchError.unknown)
        }

        guard (200...299).contains(httpResponse.statusCode) else {
            // In a real app, you might want to throw a specific error based on status code.
            return.failure(DataFetchError.httpError(statusCode: httpResponse.statusCode))
        }

        let decodedObject = try JSONDecoder().decode(T.self, from: data)
        return.success(decodedObject)

    } catch {
        if let decodingError = error as? DecodingError {
            return.failure(DataFetchError.decodingError(error))
        } else if let urlError = error as? URLError {
            return.failure(DataFetchError.networkError(urlError))
        } else {
            return.failure(DataFetchError.unknown)
        }
    }
}

